mapper.select:
SELECT * FROM (SELECT CO.CO_ID, CO.CO_NM, CO.USE_FLG, CO.CO_TP_CD, CO.CO_FRGN_NM, CO.TAX_CD, CO.TAX_OFC, CO.CO_LOCL_NM, CO.CO_ADDR_VAL_1 AS co_addr_val1, CO.CO_ADDR_VAL_2 AS co_addr_val2, CO.CO_ADDR_VAL_3 AS co_addr_val3, CO.EML_ADDR AS eml_addr, CO.FAX_NO AS fax_no, CO.PHN_NO AS phn_no, CO.SL_REP AS sl_rep, CO.WEB_ADDR AS web_addr, CO.CO_DESC AS co_desc, CO.CO_ANV_DT AS co_anv_dt, CO.CO_SZ AS co_sz, CO.CO_NTN AS co_ntn, CO.EMPE_SZ AS empe_sz, CO.CURR_CD AS curr_cd, CO.CO_INDUS_ZN AS co_indus_zn, CO.CO_PROD AS co_prod, CO.TM_ZN AS tm_zn, CO.LGO_FILE_ID AS lgoFileId, CO.CRE_DT, CO.CRE_USR_ID, CO.UPD_DT, CO.UPD_USR_ID, CO.BANK_TP_CD, CO.BANK_ACCT_NO, CO.BANK_NM AS bank_nm, CO.CHTR_CAPI_VAL AS chtr_capi_val, CO.ESTB_DT AS estb_dt FROM ADM_CO CO WHERE 1=1
AND CO.CO_ID = #{coId}
AND ( CO.CO_ID ILIKE '%' || #{searchText} || '%' OR CO.CO_NM ILIKE '%' || #{searchText} || '%' OR CO.TAX_CD ILIKE '%' || #{searchText} || '%' )
AND CO.USE_FLG = #{useFlg}
AND CO.TAX_CD ILIKE '%' || #{taxCd} || '%'
AND CO.CO_TP_CD = #{coTpCd}
AND CO.CO_NTN = #{coNtn}
ORDER BY ${sort.sortField} ${sort.sortType}, CO.UPD_DT DESC
ORDER BY CO.UPD_DT DESC
) AS CO_LIST WHERE 1=1
LIMIT #{pagination.pageSize} OFFSET (#{pagination.current} - 1) * #{pagination.pageSize}

SELECT COUNT(*) 
FROM ADM_CO 
WHERE 1=1

	AND CO_ID = #{coId}


	AND (
		CO_ID ILIKE '%' || #{searchText} || '%'
		OR CO_NM ILIKE '%' || #{searchText} || '%'
		OR TAX_CD ILIKE '%' || #{searchText} || '%'
	)


	AND USE_FLG = #{useFlg}


	AND TAX_CD ILIKE '%' || #{taxCd} || '%'


	AND CO_TP_CD = #{coTpCd}


	AND CO_NTN = #{coNtn}

SELECT CO.CO_ID, CO.CO_NM, CO.USE_FLG, CO.CO_TP_CD, CO.CO_FRGN_NM, CO.TAX_CD, CO.TAX_OFC, CO.CO_LOCL_NM, CO.CO_ADDR_VAL_1 AS co_addr_val1, CO.CO_ADDR_VAL_2 AS co_addr_val2, CO.CO_ADDR_VAL_3 AS co_addr_val3, CO.EML_ADDR AS eml_addr, CO.FAX_NO AS fax_no, CO.PHN_NO AS phn_no, CO.SL_REP AS sl_rep, CO.WEB_ADDR AS web_addr, CO.CO_DESC AS co_desc, CO.CO_ANV_DT AS co_anv_dt, CO.CO_SZ AS co_sz, CO.CO_NTN AS co_ntn, CO.EMPE_SZ AS empe_sz, CO.CURR_CD AS curr_cd, CO.CO_INDUS_ZN AS co_indus_zn, CO.CO_PROD AS co_prod, CO.TM_ZN AS tm_zn, CO.LGO_FILE_ID AS lgoFileId, CO.CRE_DT, CO.CRE_USR_ID, CO.UPD_DT, CO.UPD_USR_ID, CO.BANK_TP_CD, CO.BANK_ACCT_NO, CO.BANK_NM AS bank_nm, CO.CHTR_CAPI_VAL AS chtr_capi_val, CO.ESTB_DT AS estb_dt FROM ADM_CO CO WHERE 1=1
AND CO.CO_ID = #{coId}
AND CO.CO_NM ILIKE '%' || #{searchText} || '%'
AND CO.USE_FLG = #{useFlg}
LIMIT 1

SELECT CO_ID, CO_NM, TAX_CD FROM ADM_CO WHERE TAX_CD = #{taxCd} AND TAX_CD IS NOT NULL AND TAX_CD != ''
AND CO_ID != #{excludeCoId}
LIMIT 1
